{"script":"const fs = require('fs');
const path = require('path');

const workDir = '/Users/orion/Documents/大都会-申电云/需求单';

function listFilesRecursive(dir, depth = 0) {
  const results = [];
  const items = fs.readdirSync(dir, { withFileTypes: true });

  for (const item of items) {
    const fullPath = path.join(dir, item.name);
    const relativePath = path.relative(workDir, fullPath);

    if (item.isDirectory()) {
      results.push({ name: item.name, path: relativePath, type: 'directory' });
      results.push(...listFilesRecursive(fullPath, depth + 1));
    } else {
      results.push({ name: item.name, path: relativePath, type: 'file', size: fs.statSync(fullPath).size });
    }
  }

  return results;
}

const files = listFilesRecursive(workDir);
console.log(JSON.stringify(files, null, 2));
